SKILL_DESCRIPTION_MAX_LENGTH = 20000


SKILL_CONTENT_MAX_LENGTH = 200000


def _add_skills_list_arguments(parser: argparse.ArgumentParser) -> None:
    _ = parser


def _build_skills_list_arguments(args: argparse.Namespace) -> dict[str, Any]:
    _ = args
    return {}


def _add_skills_get_arguments(parser: argparse.ArgumentParser) -> None:
    parser.add_argument("--name", required=True)
    parser.add_argument("--offset", type=int, default=0)
    parser.add_argument("--limit", type=int, default=1000)


def _build_skills_get_arguments(args: argparse.Namespace) -> dict[str, Any]:
    return {
        "name": args.name,
        "offset": args.offset,
        "limit": args.limit,
    }


def _add_skills_create_arguments(parser: argparse.ArgumentParser) -> None:
    parser.add_argument("--name", required=True)
    parser.add_argument("--workspace-id")
    parser.add_argument("--description")
    parser.add_argument("--reference-json")
    parser.add_argument("--is-active", action=argparse.BooleanOptionalAction, default=True)
    parser.add_argument("--is-public", action=argparse.BooleanOptionalAction, default=False)
    content = parser.add_mutually_exclusive_group(required=True)
    content.add_argument("--content")
    content.add_argument("--content-file")
    parser.add_argument("--dry-run", action="store_true")


def _build_skills_create_arguments(args: argparse.Namespace) -> dict[str, Any]:
    payload: dict[str, Any] = {
        "name": args.name,
        "description": args.description,
        "content": _skill_content_argument(args),
        "is_active": args.is_active,
        "is_public": args.is_public,
    }
    if args.workspace_id is not None:
        payload["workspace_id"] = args.workspace_id
    if args.reference_json is not None:
        payload["reference"] = _json_argument(args.reference_json, field="--reference-json")
    return payload


def _add_skills_update_arguments(parser: argparse.ArgumentParser) -> None:
    parser.add_argument("--name", required=True)
    parser.add_argument("--description")
    parser.add_argument("--reference-json")
    parser.add_argument("--is-active", action=argparse.BooleanOptionalAction, default=None)
    parser.add_argument("--is-public", action=argparse.BooleanOptionalAction, default=None)
    content = parser.add_mutually_exclusive_group()
    content.add_argument("--content")
    content.add_argument("--content-file")
    parser.add_argument("--dry-run", action="store_true")


def _build_skills_update_arguments(args: argparse.Namespace) -> dict[str, Any]:
    payload: dict[str, Any] = {"name": args.name}
    if args.description is not None:
        payload["description"] = args.description
    if args.reference_json is not None:
        payload["reference"] = _json_argument(args.reference_json, field="--reference-json")
    if args.content is not None or args.content_file is not None:
        payload["content"] = _skill_content_argument(args)
    if args.is_active is not None:
        payload["is_active"] = args.is_active
    if args.is_public is not None:
        payload["is_public"] = args.is_public
    return payload


def _skill_content_argument(args: argparse.Namespace) -> str:
    content = getattr(args, "content", None)
    if content is not None:
        return str(content)
    content_file = getattr(args, "content_file", None)
    if content_file is None:
        return ""
    return Path(content_file).read_text(encoding="utf-8")


def _json_argument(value: str, *, field: str) -> Any:
    try:
        return json.loads(value)
    except json.JSONDecodeError as exc:
        raise ValueError(f"{field} must be valid JSON: {exc.msg}") from exc


def _skills_list_input_schema() -> dict[str, Any]:
    return {"type": "object", "properties": {}, "required": []}


def _skills_get_input_schema() -> dict[str, Any]:
    return {
        "type": "object",
        "properties": {
            "name": {"type": "string", "minLength": 1},
            "offset": {"type": "integer", "minimum": 0, "default": 0},
            "limit": {"type": "integer", "minimum": 1, "maximum": 1000, "default": 1000},
        },
        "required": ["name"],
    }


def _skills_create_input_schema() -> dict[str, Any]:
    return {
        "type": "object",
        "properties": {
            "name": {"type": "string", "minLength": 1, "maxLength": 80},
            "workspace_id": {"type": "string", "minLength": 1},
            "description": {"type": "string", "maxLength": SKILL_DESCRIPTION_MAX_LENGTH},
            "reference": {"description": "Optional JSON metadata for this skill."},
            "content": {"type": "string", "minLength": 1, "maxLength": SKILL_CONTENT_MAX_LENGTH},
            "is_active": {"type": "boolean", "default": True},
            "is_public": {"type": "boolean", "default": False},
        },
        "required": ["name", "content"],
    }


def _skills_update_input_schema() -> dict[str, Any]:
    return {
        "type": "object",
        "properties": {
            "name": {"type": "string", "minLength": 1, "maxLength": 80},
            "description": {"type": "string", "maxLength": SKILL_DESCRIPTION_MAX_LENGTH},
            "reference": {"description": "Optional JSON metadata for this skill."},
            "content": {"type": "string", "minLength": 1, "maxLength": SKILL_CONTENT_MAX_LENGTH},
            "is_active": {"type": "boolean"},
            "is_public": {"type": "boolean"},
        },
        "required": ["name"],
    }


