# ---- executors (generated from main.py direct_* chains) ----
async def _execute_create(ctx: CommandContext) -> Any:
    cfg = ctx.cfg
    arguments = ctx.arguments
    api_data = ctx.api_data
    payload = dict(arguments)
    if ctx.workspace_id and "workspace_id" not in payload:
        payload["workspace_id"] = ctx.workspace_id
    return await api_data(cfg, "POST", "/agent-cli/skills", json_body=payload)


async def _execute_get(ctx: CommandContext) -> Any:
    cfg = ctx.cfg
    arguments = ctx.arguments
    api_data = ctx.api_data
    name = str(arguments.get("name") or "")
    if not name:
        raise RuntimeError("missing_skill_name")
    return await api_data(
        cfg,
        "GET",
        f"/agent-cli/skills/{name}",
        params=compact_params(
            {
                "offset": arguments.get("offset", 0),
                "limit": arguments.get("limit", 1000),
                "workspace_id": ctx.workspace_id,
            }
        ),
    )


async def _execute_list(ctx: CommandContext) -> Any:
    cfg = ctx.cfg
    api_data = ctx.api_data
    return await api_data(
        cfg,
        "GET",
        "/agent-cli/skills",
        params=compact_params({"workspace_id": ctx.workspace_id}),
    )


async def _execute_update(ctx: CommandContext) -> Any:
    cfg = ctx.cfg
    arguments = ctx.arguments
    api_data = ctx.api_data
    name = str(arguments.get("name") or "")
    if not name:
        raise RuntimeError("missing_skill_name")
    payload = {key: value for key, value in arguments.items() if key != "name"}
    return await api_data(cfg, "PATCH", f"/agent-cli/skills/{name}", json_body=payload)


EXECUTORS = {
    "skills.create": direct_enveloped(_execute_create),
    "skills.get": direct_enveloped(_execute_get, with_workspace=False),
    "skills.list": direct_enveloped(_execute_list, with_workspace=False),
    "skills.update": direct_enveloped(_execute_update, with_workspace=False),
}
